class Solution:
    def maximumDifference(self, nums):
        n = len(nums)
        best = -1
        for i in range(n):
            for j in range(i + 1, n):
                if nums[i] < nums[j] and nums[j] - nums[i] > best:
                    best = nums[j] - nums[i]
        return best

