class Solution:
    def maximumDifference(self, nums):
        best = -1
        min_so_far = nums[0]
        for x in nums[1:]:
            if x > min_so_far:
                if x - min_so_far > best:
                    best = x - min_so_far
            else:
                min_so_far = x
        return best

