var maximumDifference = function(nums) {
    let best = -1;
    let minSoFar = nums[0];
    for (let i = 1; i < nums.length; i++) {
        const x = nums[i];
        if (x > minSoFar) {
            if (x - minSoFar > best) best = x - minSoFar;
        } else {
            minSoFar = x;
        }
    }
    return best;
};
